private:
        template <typename T, size_t alignment>
        struct alignas(alignment) WithAlignment : T {
                using T::T;
        };

    template <typename T, size_t alignment>
    using WithAlignmentAtLeast = WithAlignment<T, std::max(alignof(T), alignment)>;

