class Bar
{
 public:
  constexpr Bar() : dst{}
  {
  }
  std::int8_t dst[6];
};

void test(Bar& b)
{
	std::cout << "staring memcpy.\n";

	std::cout << "size of bytes to be copied: " << sizeof(txt) <<"\n";
	std::cout << "dst array size: " << sizeof(b.dst) << "\n";
	std::memcpy(b.dst, txt, sizeof(txt));
}

class Base
{
public:
	virtual ~Base() = default;
	virtual void func() = 0;

};

